import{_ as t,o as e,c as a,Q as n}from"./chunks/framework.b67c47e6.js";const m=JSON.parse('{"title":"MOB v1 Machine File","description":"","frontmatter":{},"headers":[],"relativePath":"guide/machine_files/formats/panel_mob1/index.md","filePath":"guide/machine_files/formats/panel_mob1/index.md","lastUpdated":1773939149000}'),s={name:"guide/machine_files/formats/panel_mob1/index.md"},o=n(`<h1 id="mob-v1-machine-file" tabindex="-1">MOB v1 Machine File <a class="header-anchor" href="#mob-v1-machine-file" aria-label="Permalink to &quot;MOB v1 Machine File&quot;">​</a></h1><p>The MOB v1 is a text-based machine file format used to send manufacturing instructions to automated timber wall panel processing machines like the Mobi One.</p><nav class="table-of-contents"><ul><li><a href="#what-it-contains">What It Contains</a><ul><li><a href="#layers">Layers</a></li><li><a href="#operation-types">Operation Types</a></li></ul></li><li><a href="#file-structure">File Structure</a></li><li><a href="#generation-options">Generation Options</a></li><li><a href="#output">Output</a></li><li><a href="#mob-v1-vs-mob-v2">MOB v1 vs. MOB v2</a></li></ul></nav><h2 id="what-it-contains" tabindex="-1">What It Contains <a class="header-anchor" href="#what-it-contains" aria-label="Permalink to &quot;What It Contains&quot;">​</a></h2><p>A MOB v1 file describes all the operations needed to process a wall panel. It is organized into <strong>layers</strong> (representing different faces/sides of the panel), each containing a sequence of <strong>operation commands</strong>.</p><h3 id="layers" tabindex="-1">Layers <a class="header-anchor" href="#layers" aria-label="Permalink to &quot;Layers&quot;">​</a></h3><p>Each layer represents a work zone on the panel:</p><ul><li><strong>Inside layers</strong> — The inner face of the panel.</li><li><strong>Center/wood layers</strong> — The framing structure (studs, plates).</li><li><strong>Outside layers</strong> — The outer face of the panel.</li></ul><h3 id="operation-types" tabindex="-1">Operation Types <a class="header-anchor" href="#operation-types" aria-label="Permalink to &quot;Operation Types&quot;">​</a></h3><table><thead><tr><th>Operation</th><th>Description</th></tr></thead><tbody><tr><td><strong>Framing</strong></td><td>Beam cuts, angle cuts, vertical and horizontal cuts for frame members.</td></tr><tr><td><strong>Nailing</strong></td><td>Line nailing patterns with configurable spacing for fastening cladding and battens.</td></tr><tr><td><strong>Plate positioning</strong></td><td>Cladding plate placement coordinates.</td></tr><tr><td><strong>Milling</strong></td><td>Routing paths, circles, and ellipses for openings and cutouts.</td></tr><tr><td><strong>Sawing</strong></td><td>Transverse cuts across the panel.</td></tr><tr><td><strong>Drilling</strong></td><td>Hole positions for connections and hardware.</td></tr><tr><td><strong>Gluing</strong></td><td>Adhesive application lines for bonding.</td></tr></tbody></table><h2 id="file-structure" tabindex="-1">File Structure <a class="header-anchor" href="#file-structure" aria-label="Permalink to &quot;File Structure&quot;">​</a></h2><p>The MOB file is plain text with semicolon-terminated command rows:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">VERSION 3.00;</span></span>
<span class="line"><span style="color:#e1e4e8;">TXT # MOB Conversion by Produuz.it;</span></span>
<span class="line"><span style="color:#e1e4e8;">REIHE inside;</span></span>
<span class="line"><span style="color:#e1e4e8;">ELN DesignName;</span></span>
<span class="line"><span style="color:#e1e4e8;">ELM max_x, max_y, height, scale, 0, 0;</span></span>
<span class="line"><span style="color:#e1e4e8;">Layer [zone details];</span></span>
<span class="line"><span style="color:#e1e4e8;">[operation commands]</span></span>
<span class="line"><span style="color:#e1e4e8;">End Layer;</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">VERSION 3.00;</span></span>
<span class="line"><span style="color:#24292e;">TXT # MOB Conversion by Produuz.it;</span></span>
<span class="line"><span style="color:#24292e;">REIHE inside;</span></span>
<span class="line"><span style="color:#24292e;">ELN DesignName;</span></span>
<span class="line"><span style="color:#24292e;">ELM max_x, max_y, height, scale, 0, 0;</span></span>
<span class="line"><span style="color:#24292e;">Layer [zone details];</span></span>
<span class="line"><span style="color:#24292e;">[operation commands]</span></span>
<span class="line"><span style="color:#24292e;">End Layer;</span></span></code></pre></div><p>Each command has a code (e.g., <code>NRZ</code>, <code>BR</code>, <code>PSG</code>) followed by numeric parameters defining positions, dimensions, and tool settings.</p><h2 id="generation-options" tabindex="-1">Generation Options <a class="header-anchor" href="#generation-options" aria-label="Permalink to &quot;Generation Options&quot;">​</a></h2><p>When generating MOB v1 files, you can configure:</p><table><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><strong>Starting side</strong></td><td>Begin processing from the inside or outside face.</td></tr><tr><td><strong>Shift mode</strong></td><td>How operations are shifted between layers (none, by layer, by operation).</td></tr><tr><td><strong>Nailing pattern</strong></td><td>Regular, large panel, or optimized nail placement.</td></tr><tr><td><strong>CTC spacing</strong></td><td>Center-to-center distance for nail lines.</td></tr><tr><td><strong>Mill direction</strong></td><td>Clockwise or counter-clockwise per zone.</td></tr><tr><td><strong>Tool assignments</strong></td><td>Which nailer, saw, or mill unit to use per zone.</td></tr><tr><td><strong>Operation trimming</strong></td><td>Automatically trim operations that exceed machine limits.</td></tr></tbody></table><h2 id="output" tabindex="-1">Output <a class="header-anchor" href="#output" aria-label="Permalink to &quot;Output&quot;">​</a></h2><ul><li><strong>Format:</strong> ZIP containing one <code>.mob</code> file per assembly</li><li><strong>Requires:</strong> A production line with a configured machine (e.g., Mobi One)</li></ul><h2 id="mob-v1-vs-mob-v2" tabindex="-1">MOB v1 vs. MOB v2 <a class="header-anchor" href="#mob-v1-vs-mob-v2" aria-label="Permalink to &quot;MOB v1 vs. MOB v2&quot;">​</a></h2><table><thead><tr><th></th><th>MOB v1</th><th>MOB v2</th></tr></thead><tbody><tr><td><strong>Machine</strong></td><td>Mobi One V1</td><td>Mobi One V2</td></tr><tr><td><strong>Carriages</strong></td><td>Single carriage</td><td>Dual carriages (left + right)</td></tr><tr><td><strong>Flooring</strong></td><td>Not supported</td><td>Multi-station flooring operations</td></tr><tr><td><strong>Tool control</strong></td><td>Basic tool selection</td><td>Granular per-carriage tool zones</td></tr><tr><td><strong>Complexity</strong></td><td>Simpler, widely used</td><td>More advanced, newer installations</td></tr></tbody></table>`,21),r=[o];function i(l,d,p,c,h,g){return e(),a("div",null,r)}const f=t(s,[["render",i]]);export{m as __pageData,f as default};
